const express = require('express');
const bodyParser = require('body-parser');
const session = require('express-session');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();
const port = 3000;

const accountSid = process.env.TWILIO_ACCOUNT_SID;
const authToken = process.env.TWILIO_AUTH_TOKEN;
const twilioClient = twilio(accountSid, authToken);

app.use(bodyParser.json());
app.use(bodyParser.urlencoded({ extended: true }));
app.use(session({
    secret: crypto.randomBytes(32).toString('hex'),
    resave: false,
    saveUninitialized: true,
    cookie: { secure: true }
}));

const users = {}; // In-memory user storage

function generateCode() {
    return Math.floor(100000 + Math.random() * 900000).toString();
}

app.post('/send-code', (req, res) => {
    const { phoneNumber } = req.body;

    if (!/^\+?[1-9]\d{1,14}$/.test(phoneNumber)) {
        return res.status(400).send('Invalid phone number format.');
    }

    const code = generateCode();
    req.session.code = code;
    req.session.phoneNumber = phoneNumber;

    twilioClient.messages.create({
        body: `Your verification code is ${code}`,
        from: process.env.TWILIO_PHONE_NUMBER,
        to: phoneNumber
    })
    .then(() => res.send('Verification code sent.'))
    .catch(err => res.status(500).send('Error sending SMS.'));
});

app.post('/verify-code', (req, res) => {
    const { code } = req.body;

    if (req.session.code && req.session.code === code) {
        req.session.authenticated = true;
        return res.send('Code verified successfully.');
    }

    return res.status(400).send('Invalid code.');
});

app.get('/protected', (req, res) => {
    if (req.session.authenticated) {
        return res.send('This is a protected route.');
    }
    return res.status(403).send('Access denied.');
});

app.listen(port, () => {
    console.log(`Server running at http://localhost:${port}`);
});